		if(0 != (h_offsets[i] % 4))	h_offsets[i] = (h_offsets[i] & ~3) + 4; 
	}
	for(int i=1; i<DIVISIONS; i++) h_offsets[i] = h_offsets[i-1] + h_offsets[i]; 
	for(int i=DIVISIONS - 1; 0 < i; i--) h_offsets[i] = h_offsets[i-1]; 
